effect.shader:
const vec3 luminanceWeighting = vec3(0.2126, 0.7152, 0.0722);

void main() {

    highp mat3 rgb2yuv = mat3(
         0.299,     0.587,    0.114,
        -0.14713,  -0.28886,  0.436,
         0.615,    -0.51499, -0.10001
    );
    highp mat3 yuv2rgb = mat3(
        1.0,  0.0,      1.13983,
        1.0, -0.39465, -0.58060,
        1.0,  2.03211,  0.0
    );

    vec4 glow = texture2DCv(hblur.texture, acScreenNorm.st);
    vec4 base = texture2DCv(inputImg.texture, acScreenNorm.st);
    glow.rgb /= glow.a;
    base.rgb /= base.a;
    glow.rgb = pow(glow.rgb, vec3(max(0.0001,3.-spread)));
    base.rgb = pow(base.rgb,vec3(1.0/gamma));
    base.rgb = ((base.rgb * rgb2yuv) + vec3(brightness,0.,0.)) * yuv2rgb;
    base.rgb = saturate(base.rgb);
    float lum = dot(luminanceWeighting, glow.rgb);
    float fill = 1.0;
    glow.rgb *= glow.a;
    base.rgb *= base.a;
    gl_FragColor = (mix(base,base*tintColor,tint)*fill) + mix(glow * mix(lum,1.,fill), fillColor*lum, max(saturate(blend)*(1.-lum),blend-1.0) );
}
